window.BCS_STUDY=window.BCS_STUDY||{version:'2026.07',subjects:{}};Object.assign(window.BCS_STUDY.subjects,{"bangla":{"title":"বাংলা ভাষা ও সাহিত্য","modules":[{"id":"bangla-grammar","title":"ব্যাকরণ: শব্দ, পদ ও বাক্য","intro":"শব্দের গঠন, পদভেদ, কারক-বিভক্তি, বাক্যের প্রকৃতি এবং শুদ্ধ প্রয়োগ BCS-এর সর্বাধিক পুনরাবৃত্ত অংশগুলোর একটি।","points":["শব্দের উৎস: তৎসম, তদ্ভব, দেশি ও বিদেশি—উদাহরণসহ পার্থক্য শিখুন।","বিশেষ্য, সর্বনাম, বিশেষণ, ক্রিয়া, ক্রিয়াবিশেষণ, অনুসর্গ, যোজক ও আবেগসূচক পদ চিনুন।","কারক অর্থগত সম্পর্ক; বিভক্তি শব্দে যুক্ত চিহ্ন—দুটিকে এক মনে করবেন না।","সরল, জটিল ও যৌগিক বাক্যের উপবাক্য ও সংযোজক শনাক্ত করুন।","কর্তা–ক্রিয়ার সঙ্গতি ও সর্বনামের যথাযথ নির্দেশ শুদ্ধ বাক্যের ভিত্তি।"],"focus":["প্রতিদিন ২০টি পদভেদ ও কারক নির্ণয়","ভুল বাক্য শুদ্ধ করার অনুশীলন","একই ভাব সরল–জটিল–যৌগিক বাক্যে রূপান্তর"],"sources":[{"title":"NCTB বাংলা ভাষার ব্যাকরণ ও নির্মিতি","url":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"title":"বাংলা একাডেমি ব্যাকরণ বিষয়ক প্রকাশনা","url":"https://esales.banglaacademy.gov.bd/category/%E0%A6%AC%E0%A7%8D%E0%A6%AF%E0%A6%BE%E0%A6%95%E0%A6%B0%E0%A6%A3-%E0%A6%AC%E0%A6%BF%E0%A6%B7%E0%A7%9F%E0%A6%95"}]},{"id":"bangla-wordformation","title":"সন্ধি, সমাস, উপসর্গ ও প্রত্যয়","intro":"শব্দ গঠনের নিয়ম বুঝে অনুশীলন করলে মুখস্থনির্ভরতা কমে এবং অপরিচিত শব্দও বিশ্লেষণ করা যায়।","points":["সন্ধিতে পাশাপাশি ধ্বনির পরিবর্তন ঘটে; স্বর, ব্যঞ্জন ও বিসর্গ সন্ধি আলাদা করুন।","সমাসে একাধিক পদ সংক্ষেপে এক পদে রূপ নেয়; ব্যাসবাক্য দিয়ে ধরন শনাক্ত করুন।","তৎপুরুষে উত্তরপদের অর্থ প্রধান, বহুব্রীহিতে সমাসবদ্ধ পদ অন্য কিছুকে বোঝায়।","উপসর্গ শব্দের আগে যুক্ত হয়ে অর্থ বদলায়; প্রত্যয় শেষে যুক্ত হয়ে নতুন শব্দ গঠন করে।","কৃৎপ্রত্যয় ধাতুর সঙ্গে এবং তদ্ধিত প্রত্যয় নামশব্দের সঙ্গে যুক্ত হয়।"],"focus":["সমাসের ব্যাসবাক্য লিখুন","সন্ধি বিচ্ছেদ ও সন্ধি গঠন দুদিকেই অনুশীলন","উপসর্গ/প্রত্যয় চিহ্নিত করে মূল শব্দ বের করুন"],"sources":[{"title":"NCTB বাংলা ভাষার ব্যাকরণ ও নির্মিতি","url":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"title":"বাংলা একাডেমি ব্যাকরণ বিষয়ক প্রকাশনা","url":"https://esales.banglaacademy.gov.bd/category/%E0%A6%AC%E0%A7%8D%E0%A6%AF%E0%A6%BE%E0%A6%95%E0%A6%B0%E0%A6%A3-%E0%A6%AC%E0%A6%BF%E0%A6%B7%E0%A7%9F%E0%A6%95"}]},{"id":"bangla-literature","title":"প্রাচীন ও মধ্যযুগের সাহিত্য","intro":"চর্যাপদ থেকে বৈষ্ণব পদাবলি, মঙ্গলকাব্য ও অনুবাদ সাহিত্য পর্যন্ত ধারাবাহিকতা, রচয়িতা ও বৈশিষ্ট্য বুঝে পড়ুন।","points":["চর্যাপদ বাংলা ভাষার প্রাচীনতম কাব্যনিদর্শন; এর ভাষাকে সন্ধ্যাভাষা বলা হয়।","শ্রীকৃষ্ণকীর্তন বড়ু চণ্ডীদাসের রচনা এবং রাধা–কৃষ্ণ কাহিনিভিত্তিক।","মঙ্গলকাব্যের প্রধান ধারা: মনসামঙ্গল, চণ্ডীমঙ্গল ও ধর্মমঙ্গল।","আলাওল আরাকান রাজসভার কবি; পদ্মাবতী তাঁর বিখ্যাত অনুবাদধর্মী রচনা।","মধ্যযুগে বৈষ্ণব পদাবলি ও মুসলিম কবিদের রোমান্টিক প্রণয়কাব্য গুরুত্বপূর্ণ।"],"focus":["যুগ–কবি–রচনা তিন কলামের তালিকা","চর্যাপদের কবিনাম ও শব্দার্থ","মঙ্গলকাব্যের শাখা ও প্রধান কবি তুলনা"],"sources":[{"title":"NCTB বাংলা ভাষার ব্যাকরণ ও নির্মিতি","url":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"title":"বাংলা একাডেমি ব্যাকরণ বিষয়ক প্রকাশনা","url":"https://esales.banglaacademy.gov.bd/category/%E0%A6%AC%E0%A7%8D%E0%A6%AF%E0%A6%BE%E0%A6%95%E0%A6%B0%E0%A6%A3-%E0%A6%AC%E0%A6%BF%E0%A6%B7%E0%A7%9F%E0%A6%95"}]},{"id":"bangla-modern","title":"আধুনিক বাংলা সাহিত্য","intro":"উনিশ ও বিশ শতকের কবি, ঔপন্যাসিক, নাট্যকার, প্রাবন্ধিক এবং তাঁদের প্রধান রচনা বিষয়ভিত্তিকভাবে সাজিয়ে পড়ুন।","points":["বঙ্কিমচন্দ্র বাংলা উপন্যাসের বিকাশে অগ্রগণ্য; আনন্দমঠ ও কপালকুণ্ডলা গুরুত্বপূর্ণ।","রবীন্দ্রনাথ কবিতা, গল্প, উপন্যাস, নাটক ও প্রবন্ধ—সব ধারায় অবদান রেখেছেন।","কাজী নজরুল ইসলামের সাহিত্যে বিদ্রোহ, সাম্য, মানবতা ও সংগীতের বহুমাত্রিকতা আছে।","শরৎচন্দ্রের কথাসাহিত্যে সমাজ, নারী ও মধ্যবিত্ত জীবনের বাস্তবতা প্রবল।","জীবনানন্দ দাশ আধুনিক বাংলা কবিতায় চিত্রকল্প ও নিঃসঙ্গতার স্বতন্ত্র ভাষা নির্মাণ করেন।"],"focus":["লেখক–রচনা ফ্ল্যাশকার্ড","ছদ্মনাম ও উপাধির তালিকা","কাব্য/উপন্যাস/নাটক আলাদা করে পুনরাবৃত্তি"],"sources":[{"title":"NCTB বাংলা ভাষার ব্যাকরণ ও নির্মিতি","url":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"title":"বাংলা একাডেমি ব্যাকরণ বিষয়ক প্রকাশনা","url":"https://esales.banglaacademy.gov.bd/category/%E0%A6%AC%E0%A7%8D%E0%A6%AF%E0%A6%BE%E0%A6%95%E0%A6%B0%E0%A6%A3-%E0%A6%AC%E0%A6%BF%E0%A6%B7%E0%A7%9F%E0%A6%95"}]}]},"english":{"title":"English Language and Literature","modules":[{"id":"english-grammar","title":"Grammar: Parts of Speech and Agreement","intro":"Correct sentence construction depends on identifying word functions and matching subjects with the correct verb form.","points":["A noun names; a pronoun substitutes; an adjective modifies a noun; an adverb modifies a verb, adjective or adverb.","The true subject—not the nearest noun—determines singular or plural verb agreement.","Uncountable nouns such as information, advice and furniture normally take singular verbs.","Each, every, either and neither usually take singular verbs in standard exam grammar.","Parallel structures should use the same grammatical form in a series."],"focus":["Identify parts of speech in complete sentences","Practise subject–verb agreement with intervening phrases","Correct parallelism and pronoun-reference errors"],"sources":[{"title":"British Council LearnEnglish Grammar","url":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"title":"Purdue OWL Grammar","url":"https://owl.purdue.edu/owl/general_writing/grammar/index.html"}]},{"id":"english-tensevoice","title":"Tense, Voice and Narration","intro":"BCS questions frequently test tense sequence, passive transformation and reported speech through context rather than isolated rules.","points":["Use present perfect for past actions connected to the present; use simple past for completed past time.","In passive voice, the object becomes subject and the tense is carried by the auxiliary be.","Only transitive verbs normally form a direct passive construction.","Reported speech often shifts tense back when the reporting verb is past, unless the statement remains universally true.","Time and place words may change in narration: today→that day, here→there, tomorrow→the next day."],"focus":["Transform active and passive without changing tense","Convert direct to indirect speech","Choose tense from time markers and context"],"sources":[{"title":"British Council LearnEnglish Grammar","url":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"title":"Purdue OWL Grammar","url":"https://owl.purdue.edu/owl/general_writing/grammar/index.html"}]},{"id":"english-vocab","title":"Vocabulary, Idioms and Usage","intro":"Vocabulary marks come from meaning in context, common collocations, phrasal verbs, idioms and easily confused words.","points":["Learn words in phrases, not alone: make a decision, heavy rain, strong argument.","Phrasal verbs may differ greatly from the base verb: put up with = tolerate.","Use context clues—definition, contrast, example and cause—to infer unfamiliar words.","Distinguish homophones and near-confusables: lose/loose, affect/effect, principal/principle.","Idioms are fixed expressions; literal translation usually gives the wrong meaning."],"focus":["Maintain a collocation notebook","Learn 10 phrasal verbs with example sentences daily","Revise confusing word pairs"],"sources":[{"title":"British Council LearnEnglish Grammar","url":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"title":"Purdue OWL Grammar","url":"https://owl.purdue.edu/owl/general_writing/grammar/index.html"}]},{"id":"english-literature","title":"English Literature: Periods and Authors","intro":"Study literature by period, movement, author and signature work rather than memorising disconnected titles.","points":["The Renaissance includes Shakespeare and Marlowe; humanism and classical influence are central.","The Romantic period values imagination, nature and emotion; Wordsworth, Coleridge, Shelley, Keats and Byron are major poets.","Victorian literature includes Dickens, the Brontës, Tennyson and Hardy, often engaging social change.","Modernism experiments with form and consciousness; Joyce, Eliot, Woolf and Yeats are key figures.","The Theatre of the Absurd is associated with Samuel Beckett and the breakdown of conventional plot and dialogue."],"focus":["Create period–author–work timelines","Separate poets, dramatists, novelists and essayists","Practise quotation and title identification"],"sources":[{"title":"British Council LearnEnglish Grammar","url":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"title":"Purdue OWL Grammar","url":"https://owl.purdue.edu/owl/general_writing/grammar/index.html"}]}]}});(()=>{'use strict';const d=window.BCS_DATA,s=Math.max(0,...d.questions.map(q=>Number(q.id)||0))+1,r=[{"subject":"bangla","topicId":"bangla-grammar","study":true,"question":"কারক ও বিভক্তির মধ্যে প্রধান পার্থক্য কী?","options":["কারক অর্থগত সম্পর্ক, বিভক্তি শব্দে যুক্ত চিহ্ন","কারক শুধু ক্রিয়া, বিভক্তি শুধু বিশেষণ","দুটি সম্পূর্ণ একই","বিভক্তি অর্থগত, কারক ধ্বনিগত"],"answer":0,"explanation":"কারক বাক্যে পদের অর্থগত সম্পর্ক বোঝায়; বিভক্তি সেই সম্পর্ক প্রকাশে শব্দে যুক্ত হতে পারে।","sourceUrl":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"subject":"bangla","topicId":"bangla-grammar","study":true,"question":"‘সুন্দর ফুল ফুটেছে’ বাক্যে ‘সুন্দর’ কোন পদ?","options":["বিশেষ্য","বিশেষণ","ক্রিয়া","যোজক"],"answer":1,"explanation":"‘সুন্দর’ ফুলের গুণ বোঝাচ্ছে, তাই এটি বিশেষণ।","sourceUrl":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"subject":"bangla","topicId":"bangla-grammar","study":true,"question":"কোনটি জটিল বাক্য?","options":["আমি গেলাম এবং সে রইল।","আমি বাড়ি গেলাম।","যখন বৃষ্টি থামল, আমরা বের হলাম।","দরজা বন্ধ করো।"],"answer":2,"explanation":"একটি প্রধান ও একটি আশ্রিত উপবাক্য থাকায় এটি জটিল বাক্য।","sourceUrl":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"subject":"bangla","topicId":"bangla-wordformation","study":true,"question":"‘রাজপুত্র’ কোন সমাসের উদাহরণ?","options":["দ্বন্দ্ব","কর্মধারয়","ষষ্ঠী তৎপুরুষ","বহুব্রীহি"],"answer":2,"explanation":"ব্যাসবাক্য ‘রাজার পুত্র’; ষষ্ঠী সম্পর্ক থাকায় ষষ্ঠী তৎপুরুষ।","sourceUrl":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"subject":"bangla","topicId":"bangla-wordformation","study":true,"question":"কৃৎপ্রত্যয় সাধারণত কিসের সঙ্গে যুক্ত হয়?","options":["ধাতু","সর্বনাম","অব্যয়","বাক্য"],"answer":0,"explanation":"কৃৎপ্রত্যয় ধাতুর সঙ্গে যুক্ত হয়ে নতুন শব্দ গঠন করে।","sourceUrl":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"subject":"bangla","topicId":"bangla-wordformation","study":true,"question":"সন্ধিতে মূলত কী ঘটে?","options":["পদের অর্থ লোপ","পাশাপাশি ধ্বনির পরিবর্তন","বাক্য সংক্ষিপ্তকরণ","শব্দের লিঙ্গ পরিবর্তন"],"answer":1,"explanation":"সন্ধি পাশাপাশি ধ্বনির মিলনজনিত পরিবর্তন।","sourceUrl":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"subject":"bangla","topicId":"bangla-literature","study":true,"question":"বাংলা ভাষার প্রাচীনতম কাব্যনিদর্শন কোনটি?","options":["শ্রীকৃষ্ণকীর্তন","চর্যাপদ","পদ্মাবতী","চণ্ডীমঙ্গল"],"answer":1,"explanation":"চর্যাপদ বাংলা ভাষা ও সাহিত্যের প্রাচীনতম নিদর্শন হিসেবে স্বীকৃত।","sourceUrl":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"subject":"bangla","topicId":"bangla-literature","study":true,"question":"‘শ্রীকৃষ্ণকীর্তন’-এর রচয়িতা কে?","options":["আলাওল","বড়ু চণ্ডীদাস","মুকুন্দরাম","বিদ্যাপতি"],"answer":1,"explanation":"বড়ু চণ্ডীদাস ‘শ্রীকৃষ্ণকীর্তন’-এর রচয়িতা।","sourceUrl":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"subject":"bangla","topicId":"bangla-literature","study":true,"question":"কোনটি মঙ্গলকাব্যের প্রধান ধারা?","options":["মনসামঙ্গল","গীতিকাব্য","সনেট","রোমান্স"],"answer":0,"explanation":"মনসামঙ্গল মঙ্গলকাব্যের অন্যতম প্রধান শাখা।","sourceUrl":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"subject":"bangla","topicId":"bangla-modern","study":true,"question":"‘আনন্দমঠ’ কার রচনা?","options":["বঙ্কিমচন্দ্র চট্টোপাধ্যায়","শরৎচন্দ্র চট্টোপাধ্যায়","রবীন্দ্রনাথ ঠাকুর","মানিক বন্দ্যোপাধ্যায়"],"answer":0,"explanation":"‘আনন্দমঠ’ বঙ্কিমচন্দ্র চট্টোপাধ্যায়ের উপন্যাস।","sourceUrl":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"subject":"bangla","topicId":"bangla-modern","study":true,"question":"কাজী নজরুল ইসলামের সাহিত্যের কেন্দ্রীয় বৈশিষ্ট্য কোনটি?","options":["শুধু প্রকৃতিচিত্র","বিদ্রোহ, সাম্য ও মানবতা","শুধু ঐতিহাসিক দলিল","শুধু রূপকথা"],"answer":1,"explanation":"নজরুলের রচনায় বিদ্রোহ, সাম্য, মানবতা ও অসাম্প্রদায়িকতা গুরুত্বপূর্ণ।","sourceUrl":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"subject":"bangla","topicId":"bangla-modern","study":true,"question":"জীবনানন্দ দাশ কোন ধারায় বিশেষভাবে পরিচিত?","options":["আধুনিক বাংলা কবিতা","মঙ্গলকাব্য","মধ্যযুগীয় অনুবাদ","লোকনাট্য"],"answer":0,"explanation":"জীবনানন্দ আধুনিক বাংলা কবিতার অন্যতম প্রধান কবি।","sourceUrl":"https://nctb.gov.bd/pages/static-pages/6922e0c0933eb65569e28767"},{"subject":"english","topicId":"english-grammar","study":true,"question":"Choose the correct sentence.","options":["Each of the players are ready.","Each of the players is ready.","Each of the player are ready.","Each players is ready."],"answer":1,"explanation":"‘Each’ takes a singular verb in standard agreement.","sourceUrl":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"subject":"english","topicId":"english-grammar","study":true,"question":"Which word is an adverb in “She spoke softly”?","options":["She","spoke","softly","none"],"answer":2,"explanation":"‘Softly’ modifies the verb ‘spoke’.","sourceUrl":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"subject":"english","topicId":"english-grammar","study":true,"question":"Which sentence has correct parallel structure?","options":["She likes reading, to swim and cycling.","She likes reading, swimming and cycling.","She likes to read, swimming and cycles.","She likes read, swim and cycling."],"answer":1,"explanation":"All three items use the same -ing form.","sourceUrl":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"subject":"english","topicId":"english-tensevoice","study":true,"question":"Choose the correct passive form of “They completed the work.”","options":["The work completed them.","The work was completed by them.","The work is completed by them yesterday.","The work has complete."],"answer":1,"explanation":"Simple past passive uses was/were + past participle.","sourceUrl":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"subject":"english","topicId":"english-tensevoice","study":true,"question":"Which sentence correctly uses the present perfect?","options":["I have seen him yesterday.","I saw him since Monday.","I have known her for five years.","I am knowing her for five years."],"answer":2,"explanation":"Present perfect is used for a state continuing to the present.","sourceUrl":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"subject":"english","topicId":"english-tensevoice","study":true,"question":"Reported speech of He said, “I am tired” is—","options":["He said that I am tired.","He said that he was tired.","He says he tired.","He said that he is tire."],"answer":1,"explanation":"With a past reporting verb, present ‘am’ usually backshifts to ‘was’.","sourceUrl":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"subject":"english","topicId":"english-vocab","study":true,"question":"“Put up with” means—","options":["construct","tolerate","display","postpone"],"answer":1,"explanation":"The phrasal verb means tolerate or endure.","sourceUrl":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"subject":"english","topicId":"english-vocab","study":true,"question":"Choose the correct collocation.","options":["powerful rain","heavy rain","hard rain","strongly rain"],"answer":1,"explanation":"‘Heavy rain’ is the standard collocation.","sourceUrl":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"subject":"english","topicId":"english-vocab","study":true,"question":"The opposite of “scarce” is—","options":["rare","limited","abundant","small"],"answer":2,"explanation":"‘Abundant’ means plentiful, the opposite of scarce.","sourceUrl":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"subject":"english","topicId":"english-literature","study":true,"question":"Who wrote “Hamlet”?","options":["Christopher Marlowe","William Shakespeare","John Milton","Samuel Beckett"],"answer":1,"explanation":"‘Hamlet’ is a tragedy by William Shakespeare.","sourceUrl":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"subject":"english","topicId":"english-literature","study":true,"question":"Which poet is associated with the Romantic period?","options":["William Wordsworth","T. S. Eliot","Geoffrey Chaucer","Samuel Beckett"],"answer":0,"explanation":"Wordsworth is a major English Romantic poet.","sourceUrl":"https://learnenglish.britishcouncil.org/free-resources/grammar"},{"subject":"english","topicId":"english-literature","study":true,"question":"Who wrote “Waiting for Godot”?","options":["Samuel Beckett","Charles Dickens","Thomas Hardy","John Keats"],"answer":0,"explanation":"The absurdist play was written by Samuel Beckett.","sourceUrl":"https://learnenglish.britishcouncil.org/free-resources/grammar"}];d.questions.push(...r.map((q,i)=>({...q,id:s+i})));})();
